import{_ as a,a as i}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as o,o as t,c as s,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Limite de frequência de usuários","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/Safety/user-rate-limits.md","filePath":"pt-BR/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),d={name:"pt-BR/Safety/user-rate-limits.md"};function l(n,e,p,u,c,m){return t(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="limite-de-frequencia-de-usuarios" tabindex="-1">Limite de frequência de usuários <a class="header-anchor" href="#limite-de-frequencia-de-usuarios" aria-label="Permalink to &quot;Limite de frequência de usuários&quot;">​</a></h1><p>O limite de frequência controla o uso quando um IP ou usuário realiza muitas ações em pouco tempo.</p><p>Em sites com upload público, esse recurso ajuda a reduzir spam, abuso e envios em massa indesejados.</p><h2 id="onde-configurar" tabindex="-1">Onde configurar <a class="header-anchor" href="#onde-configurar" aria-label="Permalink to &quot;Onde configurar&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Configurações do sistema -&gt; Segurança -&gt; Limite de frequência</span></span></code></pre></div><p><img src="'+a+`" alt="Limite de frequência" loading="lazy"></p><h2 id="principais-opcoes" tabindex="-1">Principais opções <a class="header-anchor" href="#principais-opcoes" aria-label="Permalink to &quot;Principais opções&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opção</th><th>Descrição</th></tr></thead><tbody><tr><td>Habilitar</td><td>Liga ou desliga o limite</td></tr><tr><td>Janela de tempo</td><td>Período usado para contar ações</td></tr><tr><td>Número máximo</td><td>Quantidade máxima permitida dentro da janela</td></tr><tr><td>Ação alvo</td><td>Upload ou outra operação a limitar</td></tr><tr><td>Tempo de bloqueio</td><td>Duração do bloqueio após exceder o limite</td></tr></tbody></table><h2 id="exemplo-razoavel" tabindex="-1">Exemplo razoável <a class="header-anchor" href="#exemplo-razoavel" aria-label="Permalink to &quot;Exemplo razoável&quot;">​</a></h2><p>Para upload público, comece com uma configuração moderada e ajuste conforme o uso real.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>30 ações a cada 10 minutos</span></span>
<span class="line"><span>bloqueio de 30 minutos ao exceder</span></span></code></pre></div><p>Isso costuma permitir uso normal e frear padrões claramente anormais.</p><h2 id="aviso-de-limite" tabindex="-1">Aviso de limite <a class="header-anchor" href="#aviso-de-limite" aria-label="Permalink to &quot;Aviso de limite&quot;">​</a></h2><p>Quando o limite é excedido, o usuário vê um aviso de que a ação foi recusada.</p><p><img src="`+i+'" alt="Aviso de erros frequentes" loading="lazy"></p><h2 id="dicas" tabindex="-1">Dicas <a class="header-anchor" href="#dicas" aria-label="Permalink to &quot;Dicas&quot;">​</a></h2><ul><li>Limite rígido demais pode bloquear uploads legítimos em lote.</li><li>Em sites públicos, evite deixar upload totalmente sem limite.</li><li>Combine com geolocalização por IP e gerenciamento de usuários para investigar abuso.</li><li>Se houver pico temporário esperado, você pode afrouxar o limite por um período.</li></ul>',17)])])}const g=o(d,[["render",l]]);export{f as __pageData,g as default};
